#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

int t,n;
char s[N];

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        scanf("%s%s%s",s,s,s);
        for(int i=1;i<=n;i++)
            printf("0");
        for(int i=1;i<=n;i++)
            printf("1");
        puts("0");
    }
    return 0;
}
